#let items = report_data.data.items.nodes
#let total-items = items.len()
#let out-of-stock = items.filter(i => int(i.SOH) == 0).len()
#let in-stock = total-items - out-of-stock

#let ven-badge(category) = {
  let (label, grad-a, grad-b, fg) = if category == "V" {
    ("V", rgb("#10b981"), rgb("#34d399"), white)
  } else if category == "E" {
    ("E", rgb("#f59e0b"), rgb("#fbbf24"), rgb("#451a03"))
  } else if category == "N" {
    ("N", rgb("#94a3b8"), rgb("#cbd5e1"), rgb("#334155"))
  } else {
    ("–", rgb("#e2e8f0"), rgb("#e2e8f0"), text-muted)
  }
  box(
    width: 16pt,
    height: 16pt,
    fill: gradient.linear(grad-a, grad-b),
    radius: 8pt,
    align(center + horizon, text(7.5pt, weight: "bold", fill: fg, label)),
  )
}

#let format-soh(value) = {
  let v = int(value)
  if v == 0 {
    box(
      fill: gradient.linear(rose-start, rose-end),
      radius: 3pt,
      inset: (x: 5pt, y: 1.5pt),
      text(8pt, weight: "bold", fill: white, "OUT"),
    )
  } else {
    text(weight: "medium", str(v))
  }
