// ---------------------------------------------------------------------------
// Table
// ---------------------------------------------------------------------------
#let col-widths = (52pt, 1fr, 28pt, 44pt, 58pt, 0.5fr)

// Gradient header bar
#block(
  width: 100%,
  fill: gradient.linear(primary-start, primary-end, angle: 90deg),
  radius: (top: 8pt),
