    let hcell(body, al: left) = box(
      inset: (x: 8pt, y: 8pt),
      align(al, text(8pt, weight: "bold", fill: white, tracking: 0.3pt, upper(body))),
    )
    grid(
      columns: col-widths,
      hcell[Code],
      hcell[Item Name],
      hcell[VEN],
      hcell(align(right, [SOH]), al: right),
      hcell[Location],
      hcell[Category],
    )
  },
)

// Data rows as a proper table (ensures uniform row heights)
// Data table with bottom accent bar
#block(
  width: 100%,
  clip: true,
  radius: (bottom: 8pt),
  {
    table(
      columns: col-widths,
      stroke: none,
      inset: (x: 8pt, y: 6pt),
      align: (left + horizon, left + horizon, center + horizon, right + horizon, left + horizon, left + horizon),
      fill: (_, row) => {
        let item = items.at(row)
        let is-oos = int(item.SOH) == 0
        if is-oos {
          rose-start.lighten(95%)
        } else if calc.rem(row, 2) == 0 {
          white
        } else {
          surface
        }
      },
      ..items.enumerate().map(((i, item)) => {
        let row = (
          text(weight: "medium", fill: primary-dark, font: "Menlo", size: 8pt, item.code),
          text(size: 8.5pt, item.name),
          ven-badge(item.at("venCategory", default: "")),
          format-soh(item.SOH),
          if item.locationName == "" {
            text(fill: text-muted, style: "italic", "—")
          } else {
            text(fill: text-secondary, item.locationName)
          },
          text(fill: text-secondary, size: 8.5pt, item.categoryName),
        )
        if i > 0 {
          (table.hline(stroke: 0.3pt + border-light),) + row
        } else {
          row
        }
      }).flatten(),
    )
    // Bottom gradient accent bar
    block(
      width: 100%,
      height: 3pt,
      fill: gradient.linear(primary-start, primary-end, angle: 90deg),
    )
  },
)

// ---------------------------------------------------------------------------
// Legend
// ---------------------------------------------------------------------------
#v(14pt)
#block(
  width: 100%,
  fill: surface,
  radius: 8pt,
  inset: (x: 14pt, y: 10pt),
  stroke: 0.4pt + border-light,
