    align(al, body),
  )

  let is-oos = int(item.SOH) == 0
  let row-border = if is-oos { 0.6pt + rgb("#fecaca") } else { 0.4pt + border }

  block(
    width: 100%,
    fill: if is-oos { rgb("#fef2f2") } else { bg },
    stroke: (bottom: row-border),
    grid(
      columns: col-widths,
      cell(text(weight: "medium", raw(item.code))),
      cell(item.name),
      cell(ven-badge(item.at("venCategory", default: ""))),
      cell(align(right, format-soh(item.SOH)), al: right),
      cell(
        if item.locationName == "" {
          text(fill: muted, style: "italic", "—")
        } else {
          item.locationName
        },
      ),
      cell(text(fill: muted, item.categoryName)),
    ),
  )
}

// Bottom border
#block(
  width: 100%,
  height: 3pt,
  fill: accent,
  radius: (bottom: 4pt),
)

// ---------------------------------------------------------------------------
// Summary footer
// ---------------------------------------------------------------------------
#v(10pt)
#grid(
  columns: (1fr, 1fr, 1fr),
  gutter: 8pt,
  ..{
    let stat-box(label, value, col: accent) = block(
      width: 100%,
      stroke: 0.6pt + border,
      radius: 4pt,
      inset: 10pt,
    )[
      #text(8pt, fill: muted, weight: "medium", upper(label))
      #v(2pt)
      #text(16pt, weight: "bold", fill: col, value)
    ]
    (
      stat-box("Total Items", str(total-items)),
      stat-box("Out of Stock", str(out-of-stock), col: if out-of-stock > 0 { danger } else { accent }),
      stat-box("In Stock", str(total-items - out-of-stock), col: rgb("#16a34a")),
    )
  },
)
